import { getAdminStats, getRecentActivity } from '@/src/lib/supabase/queries/dashboard';
import AdminDashboardClient from './_components/AdminDashboardClient';

export default async function AdminDashboard() {
  const [stats, activityLogs] = await Promise.all([
    getAdminStats(),
    getRecentActivity()
  ]);

  return (
    <AdminDashboardClient stats={stats} activityLogs={activityLogs} />
  );
}
